import { ChangeDetectionStrategy, Component, input } from '@angular/core';

@Component({
  selector: 'app-button',
  standalone: true,
  templateUrl: './button.component.html',
  styleUrl: './button.component.scss',
  changeDetection: ChangeDetectionStrategy.OnPush
})
export class ButtonComponent {
  readonly variant = input<'primary' | 'secondary' | 'danger'>('primary');
  readonly disabled = input(false);
  readonly type = input<'button' | 'submit' | 'reset'>('button');
}

import { ChangeDetectionStrategy, Component } from '@angular/core';

import { ButtonComponent } from '../../../ui/button/button.component';

@Component({
  selector: 'app-button-demo',
  standalone: true,
  imports: [ButtonComponent],
  templateUrl: './button-demo.component.html',
  styleUrl: './button-demo.component.scss',
  changeDetection: ChangeDetectionStrategy.OnPush
})
export class ButtonDemoComponent {}

import { Component, computed, inject } from '@angular/core';
import { DomSanitizer, SafeResourceUrl } from '@angular/platform-browser';

import { environment } from '../../environments/environment';

@Component({
  selector: 'app-design-system',
  standalone: true,
  templateUrl: './design-system.component.html',
  styleUrl: './design-system.component.scss'
})
export class DesignSystemComponent {
  private readonly sanitizer = inject(DomSanitizer);

  protected readonly zeroheightUrl = environment.zeroheightUrl;

  protected readonly safeZeroheightUrl = computed<SafeResourceUrl>(() =>
    this.sanitizer.bypassSecurityTrustResourceUrl(this.zeroheightUrl)
  );
}

import { ChangeDetectionStrategy, Component, input } from '@angular/core';

@Component({
  selector: 'app-form-field',
  standalone: true,
  templateUrl: './form-field.component.html',
  styleUrl: './form-field.component.scss',
  changeDetection: ChangeDetectionStrategy.OnPush
})
export class FormFieldComponent {
  readonly label = input<string>('');
  readonly hint = input<string>('');
  readonly error = input<string>('');
}

import { ChangeDetectionStrategy, Component } from '@angular/core';
import { FormControl, ReactiveFormsModule } from '@angular/forms';

import { ButtonComponent } from '../../../ui/button/button.component';
import { FormFieldComponent } from '../../../ui/form-field/form-field.component';

@Component({
  selector: 'app-form-field-demo',
  standalone: true,
  imports: [ReactiveFormsModule, FormFieldComponent, ButtonComponent],
  templateUrl: './form-field-demo.component.html',
  styleUrl: './form-field-demo.component.scss',
  changeDetection: ChangeDetectionStrategy.OnPush
})
export class FormFieldDemoComponent {
  readonly name = new FormControl<string>('', { nonNullable: true });
  submitted = false;

  submit(): void {
    this.submitted = true;
  }
}

